const owner = $('Config: owner/repo').item.json.owner;
const repo = $('Config: owner/repo').item.json.repo;
const dep = $('Assess Registry Facts').item.json.name;
const cur = $('Assess Registry Facts').item.json.current_version;
const latest = $('Assess Registry Facts').item.json.latest_version;
const summary = $('Agent 1 — Watcher/Triage').item.json.output.summary;
const H = { 'User-Agent': 'n8n', 'Accept': 'application/vnd.github+json' };
const meta = await this.helpers.httpRequest({ url: `https://api.github.com/repos/${owner}/${repo}`, headers: H, json: true });
const branch = meta.default_branch;
const tree = await this.helpers.httpRequest({ url: `https://api.github.com/repos/${owner}/${repo}/git/trees/${branch}?recursive=1`, headers: H, json: true });
const exts = /\.(js|jsx|ts|tsx|mjs|cjs|vue|svelte)$/i;
const files = (tree.tree || []).filter(t => t.type === 'blob' && exts.test(t.path)).slice(0, 25);
const esc = dep.replace(/[.*+?^${}()|[\]\\]/g, '\\$&');
const re = new RegExp(`(require\\(['"\`]${esc}['"\`]\\)|from ['"\`]${esc}['"\`]|import ['"\`]${esc}['"\`])`);
const affected = [];
for (const f of files) {
  try {
    const txt = await this.helpers.httpRequest({ url: `https://raw.githubusercontent.com/${owner}/${repo}/${branch}/${f.path}`, headers: { 'User-Agent': 'n8n' } });
    const s = typeof txt === 'string' ? txt : JSON.stringify(txt);
    if (re.test(s)) {
      const lines = s.split('\n').map(l => l.trim()).filter(l => l.includes(dep)).slice(0, 3);
      affected.push({ path: f.path, snippets: lines });
    }
  } catch (e) {}
}
return { json: { name: dep, current_version: cur, latest_version: latest, risk_summary: summary, total_hits: affected.length, affected_files: affected } };

