const f = $('Assess Registry Facts').item.json;
const out = $json.output;
const body = (typeof out === 'string' ? out : ((out && out.issue_body_markdown) || '')) + '\n\n---\n_Opened automatically by the Dependency EOL Firewall. Version bump is deterministic; migration notes are AI-drafted. Review before merge._';
const slug = String(f.name).replace(/[^a-zA-Z0-9._-]/g,'-');
return { json: { pkg: f.name, old_version: f.current_version, new_version: f.latest_version, branch: `eol-firewall/bump-${slug}-${f.latest_version}-${Date.now()}`, pr_title: `chore(deps): bump ${f.name} ${f.current_version} -> ${f.latest_version}`, pr_body: body } };

const p = $('Prep PR Vars').item.json;
const pj = $json;
const text = Buffer.from(pj.content, 'base64').toString('utf8');
const esc = s => String(s).replace(/[.*+?^${}()|[\]\\]/g, '\\$&');
const re = new RegExp('("' + esc(p.pkg) + '"\\s*:\\s*")([~^]?)' + esc(p.old_version) + '(")');
const newText = text.replace(re, `$1$2${p.new_version}$3`);
if (newText === text) throw new Error('version string not found for ' + p.pkg);
return { json: { new_content_b64: Buffer.from(newText).toString('base64'), file_sha: pj.sha } };

const cfg = $('Config: owner/repo').item.json;
const owner = cfg.owner, repo = cfg.repo;
const p = $('Prep PR Vars').item.json;
const defBranch = $('GH: Get Default Branch').item.json.default_branch;
const usage = $('Find Usage In Repo').item.json;
const blast = ($('Agent 2 — Blast-Radius').item.json.output) || {};
const affected = (usage.affected_files || []).slice(0, 6);
const H = { 'User-Agent': 'n8n', 'Accept': 'application/vnd.github+json' };
const files = [];
for (const a of affected) {
  try {
    const meta = await this.helpers.httpRequest({
      url: `https://api.github.com/repos/${owner}/${repo}/contents/${a.path}?ref=${p.branch}`,
      headers: H, json: true
    });
    if (meta && meta.content) {
      const content = Buffer.from(meta.content, 'base64').toString('utf8');
      files.push({ path: a.path, content, sha: meta.sha });
    }
  } catch (e) {}
}
let pkg_json_content = '', pkg_json_sha = '';
try {
  const pj = await this.helpers.httpRequest({
    url: `https://api.github.com/repos/${owner}/${repo}/contents/package.json?ref=${p.branch}`,
    headers: H, json: true
  });
  if (pj && pj.content) {
    pkg_json_content = Buffer.from(pj.content, 'base64').toString('utf8');
    pkg_json_sha = pj.sha;
  }
} catch (e) {}
let agent_input = '';
for (const f of files) {
  agent_input += `===FILE: ${f.path}===\n${f.content}\n===END===\n\n`;
}
return { json: {
  owner, repo,
  pkg: p.pkg, old_version: p.old_version, new_version: p.new_version,
  branch: p.branch, pr_title: p.pr_title, pr_body: p.pr_body, default_branch: defBranch,
  breaking_calls: blast.breaking_calls || [], used_symbols: blast.used_symbols || [],
  files, has_files: files.length > 0, file_count: files.length,
  pkg_json_content, pkg_json_sha,
  agent_input
} };

