const ctx = $('Has Source Files?').all(0);   // true-branch items, aligned with agent outputs
const inputs = $input.all();
const out = [];
for (let i = 0; i < inputs.length; i++) {
  const j = (ctx[i] && ctx[i].json) || {};
  let text = inputs[i].json.output;
  if (text && typeof text === 'object') text = text.text || JSON.stringify(text);
  text = String(text == null ? '' : text);
  const parsed = {};
  const re = /===FILE:\s*(.+?)===\r?\n([\s\S]*?)\r?\n===END===/g;
  let m;
  while ((m = re.exec(text)) !== null) {
    let path = m[1].trim();
    let content = m[2].replace(/^```[a-zA-Z0-9]*\r?\n/, '').replace(/\r?\n```\s*$/, '');
    parsed[path] = content;
  }
  const origFiles = j.files || [];
  let emitted = 0, esm = false;
  for (const f of origFiles) {
    const nc = parsed[f.path];
    if (nc === undefined) continue;
    if (nc === f.content) continue;
    if (/\brequire\s*\(/.test(f.content) && /^\s*import\s/m.test(nc)) esm = true;
    out.push({ json: {
      commit: true, owner: j.owner, repo: j.repo, path: f.path,
      new_content_b64: Buffer.from(nc, 'utf8').toString('base64'), file_sha: f.sha,
      commit_message: `refactor: migrate ${f.path} for ${j.pkg} ${j.new_version}`,
      branch: j.branch, pr_title: j.pr_title, pr_body: j.pr_body, default_branch: j.default_branch
    }});
    emitted++;
  }
  if (esm && j.pkg_json_content) {
    try {
      const obj = JSON.parse(j.pkg_json_content);
      if (!obj.type) {
        const newObj = Object.assign({ type: 'module' }, obj);
        const newPkg = JSON.stringify(newObj, null, 2) + '\n';
        out.push({ json: {
          commit: true, owner: j.owner, repo: j.repo, path: 'package.json',
          new_content_b64: Buffer.from(newPkg, 'utf8').toString('base64'), file_sha: j.pkg_json_sha,
          commit_message: `chore: set "type":"module" for ESM migration of ${j.pkg}`,
          branch: j.branch, pr_title: j.pr_title, pr_body: j.pr_body, default_branch: j.default_branch
        }});
      }
    } catch (e) {}
  }
  if (emitted === 0) {
    out.push({ json: {
      commit: false, owner: j.owner, repo: j.repo,
      branch: j.branch, pr_title: j.pr_title, pr_body: j.pr_body, default_branch: j.default_branch
    }});
  }
}
return out;

const seen = {};
const out = [];
for (const item of $input.all()) {
  const j = item.json;
  if (!j.branch) continue;
  if (seen[j.branch]) continue;
  seen[j.branch] = true;
  out.push({ json: {
    branch: j.branch, pr_title: j.pr_title, pr_body: j.pr_body, default_branch: j.default_branch
  }});
}
return out;
